import React from "react";
import "../Register/Register.css";
import img from "../../images/tloregister.png";
import { useForm } from "react-hook-form";
import { yupResolver } from "@hookform/resolvers/yup";
import * as yup from "yup";

export default function Register() {
  const {
    register,
    handleSubmit,
    watch,
    formState: { errors },
  } = useForm();

  const onSubmit = (data) => console.log(data);

  return (
    <section className="cont">
      <div className="register">
        <div className="col-1">
          <h2>Zarejestruj się</h2>
          <span>Zarejestruj swoje konto i ciesz się usługą</span>

          <form
            onSubmit={handleSubmit(onSubmit)}
            id="form"
            className="flex flex-col"
          >
            <input
              type="text"
              {...register("firstName", { required: true })}
              placeholder="Imie..."
            />
            {errors.firstName?.type === "required" &&
              "Imie użytkownika jest wymagane!"}
            <input
              type="text"
              {...register("lastName", { required: true, maxLength: 6 })}
              placeholder="Nazwisko..."
            />
            {errors.lastName?.type === "required" &&
              "Nazwisko użytkownika jest wymagane!"}
            <input
              type="text"
              {...register("email", { required: true, maxLength: 6 })}
              placeholder="E-mail..."
            />
            {errors.email?.type === "required" &&
              "E-mail użytkownika jest wymagany!"}

            <input
              type="text"
              {...register("confirmpwd")}
              placeholder="Hasło..."
            />
            {errors.firstName?.type === "required" && "Hasło  jest wymagane!"}

            <input
              type="text"
              {...register("confirmpwd")}
              placeholder="Potwierdź hasło..."
            />

            <button className="btn">Zarejestruj</button>
          </form>
        </div>
        <div className="col-2">
          <img src={img} alt="" />
        </div>
      </div>
    </section>
  );
}
